/* global console, process */
import { spawnSync } from 'node:child_process';
import { existsSync, mkdtempSync, rmSync } from 'node:fs';
import { tmpdir } from 'node:os';
import path from 'node:path';
import { performance } from 'node:perf_hooks';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const gnosisDir = path.resolve(__dirname, '../..');
const repoRoot = path.resolve(gnosisDir, '../..');
const fixturePath = path.resolve(__dirname, 'fib.ts');
const bigintFixturePath = path.resolve(__dirname, 'fib-bigint.ts');
const rustNativePath = path.resolve(__dirname, 'fib-native.rs');
const pythonNativePath = path.resolve(__dirname, 'fib.py');
const javaNativePath = path.resolve(__dirname, 'FibNative.java');
const invokeAppPath = path.resolve(__dirname, 'invoke-app.mjs');
const gnexecPath = path.resolve(gnosisDir, 'polyglot/target/release/gnexec');
const monsterPath = path.resolve(gnosisDir, 'polyglot/target/release/monster');
const gnodePath = path.resolve(gnosisDir, 'bin/gnode.js');

function readNumberSetting(flagName, envName, fallback) {
  const rawFlag = process.argv
    .slice(2)
    .find((value) => value.startsWith(`--${flagName}=`));
  const rawValue =
    rawFlag?.slice(flagName.length + 3) ??
    process.env[envName] ??
    `${fallback}`;
  const parsed = Number.parseInt(rawValue, 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

function readListSetting(flagName, envName, fallback) {
  const rawFlag = process.argv
    .slice(2)
    .find((value) => value.startsWith(`--${flagName}=`));
  const rawValue = rawFlag?.slice(flagName.length + 3) ?? process.env[envName];
  if (!rawValue) {
    return fallback;
  }
  return rawValue
    .split(',')
    .map((value) => Number.parseInt(value.trim(), 10))
    .filter((value) => Number.isFinite(value) && value >= 0);
}

const measuredRuns = readNumberSetting(
  'iterations',
  'GNODE_HIGH_FIB_LOAD_ITERATIONS',
  7
);
const warmupRuns = readNumberSetting(
  'warmup',
  'GNODE_HIGH_FIB_LOAD_WARMUP',
  1
);
const fibInputs = readListSetting('n', 'GNODE_HIGH_FIB_LOAD_N', [
  1_000, 10_000, 50_000,
]);

function percentile(sorted, ratio) {
  if (sorted.length === 0) {
    return 0;
  }
  const index = Math.min(
    sorted.length - 1,
    Math.max(0, Math.floor(sorted.length * ratio))
  );
  return sorted[index] ?? 0;
}

function summarize(samples) {
  const sorted = [...samples].sort((left, right) => left - right);
  const total = samples.reduce((sum, value) => sum + value, 0);
  return {
    meanMs: total / Math.max(1, samples.length),
    p50Ms: percentile(sorted, 0.5),
    p95Ms: percentile(sorted, 0.95),
    maxMs: sorted[sorted.length - 1] ?? 0,
    minMs: sorted[0] ?? 0,
  };
}

function runCommand(command, args, inputJson) {
  const started = performance.now();
  const result = spawnSync(command, args, {
    cwd: repoRoot,
    env: process.env,
    encoding: 'utf8',
    maxBuffer: 64 * 1024 * 1024,
  });
  const elapsedMs = performance.now() - started;
  if (result.error) {
    throw result.error;
  }
  if (result.status !== 0) {
    throw new Error(
      `${command} failed for ${inputJson}: ${result.stderr || result.stdout}`
    );
  }
  return {
    elapsedMs,
    digitCount: result.stdout.trim().length,
  };
}

function commandAvailable(command) {
  const result = spawnSync('sh', ['-lc', `command -v ${command}`], {
    cwd: repoRoot,
    encoding: 'utf8',
  });
  return result.status === 0;
}

function compileRustNative(outputDir) {
  if (!commandAvailable('rustc')) {
    return null;
  }
  const outputPath = path.join(outputDir, 'fib-native');
  const result = spawnSync(
    'rustc',
    ['--edition', '2021', '-O', rustNativePath, '-o', outputPath],
    {
      cwd: repoRoot,
      encoding: 'utf8',
    }
  );
  if (result.status !== 0) {
    throw new Error(`rustc failed:\n${result.stderr || result.stdout}`);
  }
  return outputPath;
}

function compileJavaNative(outputDir) {
  if (!commandAvailable('javac') || !commandAvailable('java')) {
    return false;
  }
  const result = spawnSync('javac', ['-d', outputDir, javaNativePath], {
    cwd: repoRoot,
    encoding: 'utf8',
  });
  if (result.status !== 0) {
    const output = `${result.stderr}\n${result.stdout}`;
    if (
      output.includes('Unable to locate a Java Runtime') ||
      output.includes('No Java runtime present')
    ) {
      return false;
    }
    throw new Error(`javac failed:\n${result.stderr || result.stdout}`);
  }
  return true;
}

const compiledOutputDir = mkdtempSync(path.join(tmpdir(), 'gnode-high-fib-'));
const rustNativeBinary = compileRustNative(compiledOutputDir);
const javaNativeAvailable = compileJavaNative(compiledOutputDir);

const runtimes = [
  {
    name: 'gnexec',
    command: gnexecPath,
    args: (inputJson) => [
      fixturePath,
      '--input-json',
      inputJson,
      '--export',
      'app',
    ],
  },
  {
    name: 'monster',
    command: monsterPath,
    args: (inputJson) => [
      fixturePath,
      '--input-json',
      inputJson,
      '--export',
      'app',
    ],
  },
  {
    name: 'gnode',
    command: process.execPath,
    args: (inputJson) => [
      gnodePath,
      'run',
      fixturePath,
      '--input-json',
      inputJson,
    ],
  },
  {
    name: 'bun-num',
    command: 'bun',
    args: (inputJson) => [invokeAppPath, fixturePath, inputJson],
  },
  {
    name: 'bun-big',
    command: 'bun',
    args: (inputJson) => [invokeAppPath, bigintFixturePath, inputJson],
  },
  {
    name: 'rust-native',
    command: rustNativeBinary,
    available: rustNativeBinary !== null,
    args: (inputJson) => [inputJson],
  },
  {
    name: 'python',
    command: 'python3',
    available: commandAvailable('python3'),
    args: (inputJson) => [pythonNativePath, inputJson],
  },
  {
    name: 'java-jvm',
    command: 'java',
    available: javaNativeAvailable,
    args: (inputJson) => ['-cp', compiledOutputDir, 'FibNative', inputJson],
  },
];

try {
  console.log('high Fibonacci load');
  console.log(`warmup=${warmupRuns} measured=${measuredRuns}`);
  const skipped = runtimes
    .filter((runtime) => runtime.available === false)
    .map((runtime) => runtime.name);
  if (skipped.length > 0) {
    console.log(`skipped: ${skipped.join(', ')}`);
  }

  for (const n of fibInputs) {
    const inputJson = JSON.stringify({ n });
    console.log(`\nfib(${n})`);
    for (const runtime of runtimes) {
      if (runtime.available === false) {
        continue;
      }
      for (let run = 0; run < warmupRuns; run += 1) {
        runCommand(runtime.command, runtime.args(inputJson), inputJson);
      }

      const samples = [];
      let digitCount = 0;
      for (let run = 0; run < measuredRuns; run += 1) {
        const sample = runCommand(
          runtime.command,
          runtime.args(inputJson),
          inputJson
        );
        samples.push(sample.elapsedMs);
        digitCount = sample.digitCount;
      }

      const summary = summarize(samples);
      console.log(
        [
          runtime.name.padEnd(11),
          `digits=${String(digitCount).padStart(6)}`,
          `mean=${summary.meanMs.toFixed(2)}ms`,
          `p50=${summary.p50Ms.toFixed(2)}ms`,
          `p95=${summary.p95Ms.toFixed(2)}ms`,
          `min=${summary.minMs.toFixed(2)}ms`,
          `max=${summary.maxMs.toFixed(2)}ms`,
        ].join(' | ')
      );
    }
  }
} finally {
  rmSync(compiledOutputDir, { recursive: true, force: true });
}
